#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
const int N=1e6+10;
struct Pair
{
	int a,b,idx;inline Pair(const int &X=0,const int &Y=0){a=X;b=Y;}
	inline bool operator<(const Pair &Q)const{return a==Q.a||b>=Q.b;}
}a[N],stk[N];int top,n,m;struct node{int l,r,idx;}t[N];
namespace Sub1
{
	inline void mian()
	{
		rep(1,m,i)
		{
			top=0;int ans=0;
			rep(t[i].l,t[i].r,j)
			{
				while(top&&a[j]<stk[top])--top;
				ans+=(!top);stk[++top]=a[j];
			}
			printf("%d\n",ans);
		}
	}
}
namespace Sub3//ordinary
{
	int L[N],ans[N],T[N];
	inline bool cmp(const node &x,const node &y){return x.r<y.r;}
	inline void add(int p){++p;while(p<=n)++T[p],p+=(p&-p);return;}
	inline int qry(int l,int r)
	{
		++r;int res=0;while(r)res+=T[r],r^=(r&-r);
		while(l)res-=T[l],l^=(l&-l);return res;
	}
	inline void mian()
	{
		top=0;rep(1,n,i)
		{
			while(top&&a[i]<stk[top])--top;
			L[i]=stk[top].idx;stk[++top]=a[i];
		}
		std::sort(t+1,t+m+1,cmp);
		int cur=0;rep(1,m,i)
		{
			while(cur<n&&cur+1<=t[i].r)add(L[++cur]);
			ans[t[i].idx]=(t[i].r-t[i].l+1)-qry(t[i].l,t[i].r);
		}
		rep(1,m,i)printf("%d\n",ans[i]);
	}
}
int main()
{
//	freopen("stack.in","r",stdin);
//	freopen("stack.out","w",stdout);
	n=read();m=read();rep(1,n,i)a[i].a=read();
	rep(1,n,i)a[i].b=read(),a[i].idx=i;
	rep(1,m,i)t[i].l=read(),t[i].r=read(),t[i].idx=i;
	if(n<=5000&&m<=5000)return Sub1::mian(),0;
	return Sub3::mian(),0;
}
